@code {
    [Parameter, EditorRequired] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool saving;

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(title)) return;
        saving = true;
        await OnSave.InvokeAsync((title, assignee, priority, dueDate));
        saving = false;
    }
}
"}

